var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"상황 발생 37분 전\\n통제실, LAKE-4 봉인 시설","JPN":"状況発生まで、あと37分\\n統制室、LAKE-4隔離施設","ENG":"37 minutes before the incident\\nControl Room, LAKE-4 Quarantine Facility","TWN":"事發前37分鐘\\n控制室，LAKE-4隔離設施"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"파편의 상태는 어떤가?","JPN":"破片の状態は？","ENG":"How's the Fragment's condition?","TWN":"碎片的狀態怎麼樣？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"활성화 반응은 17%. 그로니아 사태가 발생했던 시점에 비해 안정을 되찾아가고 있습니다.","JPN":"活性化反応は17％。グロニア事態が発生した時点に比べて、安定を取り戻しつつあります。","ENG":"The activation reaction is at 17%. Compared to when the Gronia incident occurred, it's stablising.","TWN":"活化反應17%。與格羅尼亞事件發生時相比，正在慢慢恢復穩定。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"다행이군. 기관장님의 연락은 따로 없으셨나?","JPN":"よろしい。機関長からの連絡は特になかったか？","ENG":"Good. Was there any word from Chief?","TWN":"那就好。機關長沒有另外聯絡嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"17분 전 제 1 표적을 추격 중이라는 내용이 수신되었습니다.","JPN":"17分前、第1標的を追撃中との内容を受信しました。","ENG":"We received word that she is chasing Target No. 1, 17 minutes ago.","TWN":"17分鐘前收到了正在追擊第一目標的內容。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"정말 어처구니가 없는 노릇이군…… 부통령이나 되는 인물이 대체 뭐가 아쉬워서……","JPN":"まったく理解不能だ……副大統領にもなる人物がいったいどうして……","ENG":"This is absurd... Why would someone like the vice president cooperate─","TWN":"真是無言……副總統那種大人物究竟為什麼要……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"음? 이 소리는 뭐지? 혹시 봉인에 뭔가 문제가 생긴 건가?","JPN":"む？　この音は何だ？　まさか隔離に何か問題でも発生したのか？","ENG":"Hmm? What was that? Did something go wrong with the quarantine?","TWN":"嗯？這聲音是怎麼回事？難道是隔離發生問題了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"아뇨. 활성화 반응에 변동은 없습니다.","JPN":"いいえ。活性化反応に変動はありません。","ENG":"No, sir. There is no change to the activation reaction.","TWN":"不是，活化反應沒有變化。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"관측소, 여기는 통제실. 현재 경고 신호가 감지되었다. 현장에 문제가 있나?","JPN":"観測所、こちら統制室。現在、警告信号が感知された。現場に問題はあるか？","ENG":"Observation Post, this is Control Room. We detected an alarm. Is there a problem over there? Over.","TWN":"觀測站，這裡是控制室。現在檢測到警告訊號。現場有問題嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"……관측소, 응답하라. 관측소?","JPN":"……観測所、応答せよ。観測所？","ENG":"Observation Post, do you copy? Observation Post?","TWN":"……觀測站，請回答，觀測站？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"찾는 사람들은 대답이 힘들 거야. 이미 숨쉬기도 벅찬 상태거든.","JPN":"探してる人たちはたぶん答えられないわ。すでに息もまともにできない状態だから。","ENG":"The person you're trying to reach isn't available right now. He's barely able to breathe.","TWN":"你要找的人應該沒辦法回答你了。因為他們連呼吸都困難了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"뭣……! 누군데 지금 통신망에 개입했나? 소속을 밝히도록!","JPN":"なっ……！　今、通信網に介入したのは誰だ？　所属を言え！","ENG":"Huh...?! Who is that? Identify yourself!","TWN":"什麼……！現在通訊的是誰？表明你的身份！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 한낱 떠돌이 악사야.","JPN":"ふふっ。単なる流れの楽士よ。","ENG":"Heh. I'm just a wandering troubadour.","TWN":"呵呵，我只是個浪人樂師。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"자, 연주를 들을 준비는 됐을까?","JPN":"さて、演奏を聞く準備はできているのかしら。","ENG":"Now, are you ready to hear my performance?","TWN":"好了，準備好聽我的演奏了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"지, 지휘관님! 관측소 일대에서 고준위 침식파가 감지되었습니다!","JPN":"し、指揮官！　観測所の付近一帯から、高レベルの侵食波が感知されました！","ENG":"C-Commander! High-level Corruption ray has been detected near the Observation post!","TWN":"指…指揮官！觀測站一帶檢測到了高危險侵蝕波！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"침식파라고?","JPN":"侵食波だと？","ENG":"Corruption ray?","TWN":"侵蝕波？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"기관장님께서 우려하신 대로군……. 주력은 합중국이 아니라 우릴 노리는 거였나?","JPN":"機関長が懸念されたとおりだ……主力の狙いは合衆国ではなく、我々だったのか？","ENG":"So this is what Chief was worried about... They were planning to attack us and not the States.","TWN":"果然跟機關長擔心的一樣……主力盯上的是我們，而不是合眾國嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"학회의 공격이다! 전 기관원은 전투 태세로!","JPN":"学会の攻撃だ！　全機関員は戦闘態勢を！","ENG":"The Society is attacking us! Everyone, get ready to fight!","TWN":"是學會的攻擊！全體機關成員準備戰鬥！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"해상에 대기 중인 함대에도 당장 지원을 요청하도록!","JPN":"海上で待機している艦隊にもすぐ支援を要請しろ！","ENG":"Request immediate assistance from the waiting fleet at sea!","TWN":"馬上向海上待命的艦隊請求支援！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"큰일입니다! 함대, 현재 교전 중! 통신 장애로 교신은 불가능한 상황입니다!","JPN":"大変です！　艦隊、ただいま交戦中！　通信障害で交信が不可能な状態です！","ENG":"No can do, sir! The fleet is currently engaged in combat with the enemy! Comms are down, so requesting is impossible!","TWN":"不好了！艦隊，目前正在交火！由於通訊故障，現在聯絡不上！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"전략 위성으로 촬영한 결과, 바다 속에서 올라 온 촉수들에 붙잡혀 있습니다!","JPN":"戦略衛星で撮影した結果、海の中から伸びてきた触手に捕まっています！","ENG":"According to satellite images, tentacles emerging from the ocean are blocking them!","TWN":"從戰略衛星拍攝的圖像來看，艦隊被海裡伸出來的觸手抓住了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"촉수라고……? 크라켄이라도 끌어들인 건가?","JPN":"触手だと……？　クラーケンでも引き入れたのか？","ENG":"Tentacles...? Did they summon a Kraken of some sort?","TWN":"觸手……？克拉肯也牽扯進來了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"아냐. 아무리 4종 침식체라도 함대 전체를 상대할 수 없을 텐데……","JPN":"いや。いくら第4種侵食体だとしても、艦隊全体を相手することはできないはず……","ENG":"No. Even if it's a Category 4 C.O., it can't possibly fight off an entire fleet...","TWN":"不對，就算是4類侵蝕體，也對付不了整個艦隊……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"학회 놈들…… 이번에야말로 작정을 한 건가…….","JPN":"学会め……今度こそ本気ということか……","ENG":"Those Society bastards...! Are they planning to take us all down...?","TWN":"學會那些傢伙……這次可真是來勢洶洶……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"의학부, 저격 지점에 강하 완료.","JPN":"医学部、狙撃地点に降下完了。","ENG":"Medicine Department, successfully arrived at the sniping vantage point.","TWN":"醫學院，已降落到狙擊點。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_TOUCH"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L45_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"무장한 적 병력의 움직임이 확인되었습니다.","JPN":"武装した敵の兵力の動きが確認されました。","ENG":"Movement of armed enemy forces confirmed.","TWN":"已確認敵方武裝兵力的動向。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"함대는 말씀드린 대로 저희들이 봉쇄했어요.","JPN":"艦隊はお話したとおり我々が封鎖しました。","ENG":"The fleet has been cut off, as we promised.","TWN":"已經按照命令封鎖了艦隊。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"제 지원은 여기까지랍니다. 역시 아직까지는 셋으로 나누는 것도 부담이 크네요.","JPN":"我々の支援はここまでです。やはり今はまだ三つに分かれるのも負担が大きいですね。","ENG":"However, our assistance ends here. As expected, it is still difficult to be divided into three.","TWN":"我的支援就到此為止了。果然現在分出三個分身，對我來說很吃力。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"심려치 마시지요, 왕이시여.","JPN":"ご心配なさらず、王様。","ENG":"Do not worry, my lord.","TWN":"請別擔心，我的王。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"학회에서 제가 부재 중인 동안 단원들을 거두어 주셨다고 들었습니다.","JPN":"私の不在中、学会で団員を集めてくださったと聞きました。","ENG":"I heard that the Society took our members under their wing while I was away.","TWN":"聽說學會在我不在的時候收留了團員們。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"본격적인 공연에 들어가기 전에, 전주곡은 연주해야 하겠더군요.","JPN":"本格的な公演の前に、やはり前奏曲は演奏しておきませんと。","ENG":"Before the actual performance begins, we need to play a prelude first.","TWN":"在正式開始演出之前，我要先演奏序曲。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"아니요. 저희의 뜻을 이해해 주시는 분이 계셔서 오히려 감사할 노릇이죠.","JPN":"いいえ。むしろ我々の意思を理解してくださる方がいらっしゃることに感謝しています。","ENG":"No, we are grateful to have someone who understands our cause.","TWN":"不，我反而很感激，因為有人理解我們的意志。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이미 아시겠지만, <color=#ffd34c>심연에 계신 분</color>을 이 세계까지 불러들이려면 상당한 힘이 필요하답니다.","JPN":"すでにご存じでしょうが、<color=#ffd34c>深淵にいらっしゃる方</color>をこの世界までお呼びするには、相当な力が必要になります。","ENG":"As you may already know, it will take great strength to summon <color=#ffd34c>Him in the Gulf</color> here.","TWN":"你應該已經知道了，要想讓<color=#ffd34c>深淵中的那位</color>來到這個世界，需要相當多的能量。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이 시설에 계시던 분들의 피도 필요할 수 있으니, 지나친 훼손은 지양해 주세요.","JPN":"この施設にいらっしゃった方々の血も必要になる可能性があるので、あまり傷つけないようにお願いいたします。","ENG":"We may require the blood of everyone at the facility, so please avoid causing too much damage.","TWN":"也可能需要這個設施裡的人的鮮血，所以請儘量避免過度破壞。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"학부장님도, 모쪼록 협조 부탁드려요.","JPN":"学部長も、どうかご協力のほどお願いします。","ENG":"And Dean Heydrich, thank you for your cooperation.","TWN":"學院院長，也請配合一下。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"물론이오, 학회장. 학회의 오랜 숙적에게 패배를 안겨 줄 기회가 아닌가.","JPN":"もちろんだ、学会長。学会の古い宿敵に敗北を味わわせるチャンスではないか。","ENG":"Of course, President. Isn't it time we defeated the Society's old nemesis?","TWN":"當然可以，學會長。這不正是讓學會的宿敵嘗到失敗滋味的機會嗎。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"마침 실전에서만 할 수 있는 테스트들이 떠올랐소.","JPN":"そうだ、ちょうど実戦でのみ行えるテストが思いついた。","ENG":"Furthermore, I have thought of a field test that can only be used in battle.","TWN":"我正好想到了一些只能在實戰中進行的測試。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"네. 그럼 저희는 여기 앉아서 상황이 정리될 때까지 기다릴게요.","JPN":"わかりました。では我々はここに座って、状況が落ち着くまでお待ちしています。","ENG":"Very well. Then we will wait until the situation settles down.","TWN":"嗯，那我們就坐在這裡等著事情結束吧。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"마침 샌드위치를 싸 왔거든요. 레지나 님도 함께 드실 수 있었으면 정말 기뻤을 텐데요.","JPN":"今日はサンドイッチを持ってきているんです。レジーナ様もご一緒できたならとても嬉しかったのに。","ENG":"We just happen to have brought sandwiches. It would've been nicer if Miss Regina could be here with us.","TWN":"正好我帶了三明治。如果蕾佳娜也能一起吃，我們會很開心。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"아. 리벳은 가서 소장님 쪽을 도와주실래요?","JPN":"あ。リベットは所長のお手伝いをしてくれますか？","ENG":"Oh. Rivet, could you please go help Chief?","TWN":"啊，里維，你能去幫幫所長嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"개량한 무기가 잘 작동하는지도 시험해 봐야죠.","JPN":"改良した武器がちゃんと動作するかも試したいですし。","ENG":"You should also test if the modified weapons are working properly as well.","TWN":"也要測試一下改良後的武器能否正常運轉。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"물론이지. 보수만 두둑하게 챙겨 준다면야.","JPN":"もちろんだよ。報酬さえしっかりくれればね。","ENG":"Sure! As long as you pay me!","TWN":"當然。只要給我豐厚的報酬就行。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아니! 사실 안 챙겨 줘도 돼! 이런 기회를 놓칠 수는 없지!","JPN":"あ、いいや！　別にくれなくても！　こんなチャンス、逃すわけにはいかないからね！","ENG":"No, wait! You don't have to this time! I wouldn't miss this for the world!","TWN":"不！其實不給報酬也沒關係！我可不能錯過這種機會！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"네. 당신이라면 그러실 줄 알았어요.","JPN":"はい。あなたならそう考えるだろうと思いました。","ENG":"Okay. We knew you would say that.","TWN":"嗯，我就知道你會這樣。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"……레지나 님. 조금만 기다려 주세요.","JPN":"……レジーナ様。もう少しお待ちください。","ENG":"Oh, Miss Regina... Please wait a little longer.","TWN":"……蕾佳娜，請再等等。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이제 곧…… 아무것도 걱정할 필요 없을 테니까요.","JPN":"もうすぐ……何の心配も必要なくなるでしょうから。","ENG":"Soon... You won't have to worry about anything.","TWN":"很快……你就什麼都不用擔心了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};